"""
TDD Stage: affine_transform
Full layer_norm with optional gamma (weight) and beta (bias) affine parameters.
"""

import pytest
import torch
import torch.nn.functional
import ttnn

from .layer_norm import layer_norm


def pytorch_reference(x, weight, bias):
    """PyTorch reference for this stage."""
    return torch.nn.functional.layer_norm(x, [x.shape[-1]], weight=weight, bias=bias, eps=1e-5)


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((32, 32), id="32x32"),
        pytest.param((64, 128), id="64x128"),
        pytest.param((32, 256), id="32x256"),
        pytest.param((128, 64), id="128x64"),
    ],
)
def test_affine_transform(device, shape):
    """Verify full layer_norm with optional gamma (weight) and beta (bias) affine parameters."""
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)
    weight = torch.randn(shape[-1])
    bias = torch.randn(shape[-1])

    expected = pytorch_reference(torch_input.float(), weight, bias)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )
    weight_t = ttnn.from_torch(weight, dtype=ttnn.bfloat16, layout=ttnn.ROW_MAJOR_LAYOUT, device=device)
    bias_t = ttnn.from_torch(bias, dtype=ttnn.bfloat16, layout=ttnn.ROW_MAJOR_LAYOUT, device=device)

    ttnn_output = layer_norm(ttnn_input, weight=weight_t, bias=bias_t)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.2,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
